arguments.file_text:
namespace sv_0d2b33d2a4b0425d8732fbdecfb1de01.Services;

public class ApplicationState
{
    // Step 1 – Personal Info
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;

    // Step 2 – Experience
    public List<JobEntry> JobHistory { get; set; } = [];

    // Step 3 – References
    public List<ReferenceContact> References { get; set; } = [];

    /// <summary>
    /// Tracks which steps have been explicitly completed (1-based).
    /// The layout reads this via an endpoint so the static SSR progress
    /// bar can reflect completed state even though it cannot inject
    /// the circuit-scoped service directly.
    /// </summary>
    public HashSet<int> CompletedSteps { get; } = [];

    public void MarkCompleted(int step) => CompletedSteps.Add(step);
}

public class JobEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Years { get; set; } = string.Empty;
}

public class ReferenceContact
{
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
}

@inherits LayoutComponentBase
@inject NavigationManager Nav

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="apply-header px-4 py-3">
            <h4 class="mb-3">Job Application</h4>

            <div class="step-progress">
                @for (int i = 0; i < Steps.Length; i++)
                {
                    var step = Steps[i];
                    var stepNum = i + 1;
                    var isCurrent = stepNum == CurrentStep;

                    <a href="@step.Href"
                       class="step-item @(isCurrent ? "active" : "") @(stepNum < CurrentStep ? "completed" : "")">
                        <span class="step-number">@stepNum</span>
                        <span class="step-label">@step.Label</span>
                    </a>

                    @if (stepNum < Steps.Length)
                    {
                        <div class="step-connector @(stepNum < CurrentStep ? "completed" : "")"></div>
                    }
                }
            </div>

            <p class="text-muted mt-2 mb-0">Step @CurrentStep of @Steps.Length</p>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    private record StepInfo(string Href, string Label);

    private static readonly StepInfo[] Steps =
    [
        new("apply/personal-info", "Personal Info"),
        new("apply/experience", "Experience"),
        new("apply/references", "References"),
        new("apply/review", "Review"),
    ];

    private int CurrentStep
    {
        get
        {
            var uri = Nav.ToBaseRelativePath(Nav.Uri).TrimEnd('/').ToLowerInvariant();
            for (int i = 0; i < Steps.Length; i++)
            {
                if (uri.Equals(Steps[i].Href, StringComparison.OrdinalIgnoreCase))
                    return i + 1;
            }
            return 1;
        }
    }
}

.page {
    position: relative;
    display: flex;
    flex-direction: column;
}

main {
    flex: 1;
}

.sidebar {
    background-image: linear-gradient(180deg, rgb(5, 39, 103) 0%, #3a0647 70%);
}

.apply-header {
    background-color: #f7f7f7;
    border-bottom: 1px solid #d6d5d5;
}

.step-progress {
    display: flex;
    align-items: center;
    gap: 0;
}

.step-item {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    text-decoration: none;
    color: #999;
    font-weight: 500;
    padding: 0.3rem 0.5rem;
    border-radius: 0.375rem;
    transition: all 0.15s;
}

.step-item:hover {
    text-decoration: none;
    color: #555;
}

.step-number {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 1.75rem;
    height: 1.75rem;
    border-radius: 50%;
    border: 2px solid #ccc;
    font-size: 0.85rem;
    font-weight: 600;
    flex-shrink: 0;
}

.step-label {
    font-size: 0.85rem;
}

.step-item.active {
    color: #0d6efd;
}

.step-item.active .step-number {
    border-color: #0d6efd;
    background-color: #0d6efd;
    color: #fff;
}

.step-item.completed {
    color: #198754;
}

.step-item.completed .step-number {
    border-color: #198754;
    background-color: #198754;
    color: #fff;
}

.step-connector {
    width: 2rem;
    height: 2px;
    background-color: #ccc;
    flex-shrink: 0;
}

.step-connector.completed {
    background-color: #198754;
}

@media (max-width: 640.98px) {
    .step-label {
        display: none;
    }
}

@media (min-width: 641px) {
    .page {
        flex-direction: row;
    }

    .sidebar {
        width: 250px;
        height: 100vh;
        position: sticky;
        top: 0;
    }

    .apply-header {
        position: sticky;
        top: 0;
        z-index: 1;
    }

    .apply-header, article {
        padding-left: 2rem !important;
        padding-right: 1.5rem !important;
    }
}

#blazor-error-ui {
    color-scheme: light only;
    background: lightyellow;
    bottom: 0;
    box-shadow: 0 -1px 2px rgba(0, 0, 0, 0.2);
    box-sizing: border-box;
    display: none;
    left: 0;
    padding: 0.6rem 1.25rem 0.7rem 1.25rem;
    position: fixed;
    width: 100%;
    z-index: 1000;
}

    #blazor-error-ui .dismiss {
        cursor: pointer;
        position: absolute;
        right: 0.75rem;
        top: 0.5rem;
    }

