.page {
    position: relative;
    display: flex;
    flex-direction: column;
}

main {
    flex: 1;
}

.sidebar {
    background-image: linear-gradient(180deg, rgb(5, 39, 103) 0%, #3a0647 70%);
}

.apply-header {
    background-color: #f7f7f7;
    border-bottom: 1px solid #d6d5d5;
}

.step-progress {
    display: flex;
    align-items: center;
    gap: 0;
}

.step-item {
    display: flex;
    align-items: center;
