    text-decoration: none;
    color: #999;
    font-weight: 500;
    padding: 0.3rem 0.5rem;
    border-radius: 0.375rem;
    transition: all 0.15s;
}

.step-item:hover {
    text-decoration: none;
    color: #555;
}

.step-number {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 1.75rem;
    height: 1.75rem;
    border-radius: 50%;
    border: 2px solid #ccc;
    font-size: 0.85rem;
    font-weight: 600;
    flex-shrink: 0;
}

.step-label {
    font-size: 0.85rem;
}

.step-item.active {
    color: #0d6efd;
}

.step-item.active .step-number {
    border-color: #0d6efd;
    background-color: #0d6efd;
    color: #fff;
}

.step-item.completed {
    color: #198754;
