.step-item.completed .step-number {
    border-color: #198754;
    background-color: #198754;
    color: #fff;
}

.step-connector {
    width: 2rem;
    height: 2px;
    background-color: #ccc;
    flex-shrink: 0;
}

.step-connector.completed {
    background-color: #198754;
}

@media (max-width: 640.98px) {
    .step-label {
        display: none;
    }
}

@media (min-width: 641px) {
    .page {
        flex-direction: row;
    }

