<PageTitle>Personal Info – Apply</PageTitle>

<h3>Personal Information</h3>

<EditForm Model="this" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="Name" placeholder="Jane Doe" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email Address</label>
        <InputText class="form-control" @bind-Value="Email" type="email" placeholder="jane@example.com" />
    </div>

    <div class="d-flex justify-content-end">
        <button type="submit" class="btn btn-primary">Next &rarr;</button>
    </div>
</EditForm>

@code {
    private string Name { get; set; } = string.Empty;
    private string Email { get; set; } = string.Empty;

    protected override void OnInitialized()
    {
        Name = AppState.Name;
        Email = AppState.Email;
    }

    private void Next()
    {
        AppState.Name = Name;
        AppState.Email = Email;
        AppState.MarkCompleted(1);
        Nav.NavigateTo("apply/experience");
    }
}

@page "/apply/experience"
@layout ApplyLayout
@rendermode InteractiveServer
@inject ApplicationState AppState
@inject NavigationManager Nav
@using sv_0d2b33d2a4b0425d8732fbdecfb1de01.Services

<PageTitle>Experience – Apply</PageTitle>

<h3>Work Experience</h3>

@if (Jobs.Count == 0)
{
    <p class="text-muted">No job history entries yet. Add one below.</p>
}
else
{
    <div class="table-responsive mb-3">
        <table class="table table-striped">
            <thead>
                <tr><th>Company</th><th>Title</th><th>Years</th><th></th></tr>
            </thead>
            <tbody>
                @for (int i = 0; i < Jobs.Count; i++)
                {
                    var idx = i;
                    <tr>
                        <td>@Jobs[idx].Company</td>
                        <td>@Jobs[idx].Title</td>
                        <td>@Jobs[idx].Years</td>
                        <td><button class="btn btn-sm btn-outline-danger" @onclick="() => Jobs.RemoveAt(idx)">Remove</button></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

<div class="card p-3 mb-3">
    <h6>Add Job Entry</h6>
    <div class="row g-2">
        <div class="col-md-4">
            <InputText class="form-control" @bind-Value="NewCompany" placeholder="Company" />
        </div>
        <div class="col-md-4">
            <InputText class="form-control" @bind-Value="NewTitle" placeholder="Job Title" />
        </div>
        <div class="col-md-2">
            <InputText class="form-control" @bind-Value="NewYears" placeholder="Years" />
        </div>
        <div class="col-md-2">
            <button class="btn btn-outline-primary w-100" @onclick="AddJob">Add</button>
        </div>
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick='() => Nav.NavigateTo("apply/personal-info")'>&larr; Back</button>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private List<JobEntry> Jobs { get; set; } = [];
    private string NewCompany { get; set; } = string.Empty;
    private string NewTitle { get; set; } = string.Empty;
    private string NewYears { get; set; } = string.Empty;

    protected override void OnInitialized()
    {
        Jobs = AppState.JobHistory;
    }

    private void AddJob()
    {
        if (string.IsNullOrWhiteSpace(NewCompany)) return;
        Jobs.Add(new JobEntry { Company = NewCompany, Title = NewTitle, Years = NewYears });
        NewCompany = string.Empty;
        NewTitle = string.Empty;
        NewYears = string.Empty;
    }

    private void Next()
    {
        AppState.JobHistory = Jobs;
        AppState.MarkCompleted(2);
        Nav.NavigateTo("apply/references");
    }
}

